const v = flow.get("vivarium.minimumTemperature",  "vivariumsettingsfile");
if (v !== undefined) return { payload: v };
return null;

const v = flow.get("vivarium.maximumTemperature",  "vivariumsettingsfile");
if (v !== undefined) return { payload: v };
return null;

// Toggle output each time a message arrives
let fans = context.get('fans') || false;  // get previous state, default false

fans = !fans;              // flip the state
context.set('fans', fans); // remember it

return { payload:{cooler: fans?"on":"off"} };   // send true/false (on/off)

const v = flow.get("vivarium.minimumHumidity",  "vivariumsettingsfile");
if (v !== undefined) return { payload: v };
return null;

const v = flow.get("vivarium.maximumHumidity",  "vivariumsettingsfile");
if (v !== undefined) return { payload: v };
return null;

