if (v !== undefined) return { payload: v };
return null;

const v = flow.get("vivarium.precipitationDuration",  "vivariumsettingsfile");
if (v !== undefined) return { payload: v };
return null;

const v = flow.get("vivarium.precipitationNighttimeDisable",  "vivariumsettingsfile");
if (v !== undefined) return { payload: v };
return null;

msg.topic = "night";
if( msg.payload === 'off'){
    msg.payload = true;
}
else{
    msg.payload = false;
}
return msg

// Toggle output each time a message arrives
let auxLights = context.get('auxLights') || false;  // get previous state, default false

auxLights = !auxLights;              // flip the state
context.set('auxLights', auxLights); // remember it

return { payload:{auxLighting: auxLights?"on":"off"} };   // send true/false (on/off)

if( msg.payload.test ){
    let mainLights = context.get('mainLights');
    mainLights = !mainLights;
    context.set('mainLights', mainLights);
    return { payload:{lighting: mainLights?"on":"off"} }; 
}

const v = flow.get("vivarium.uvbRequired",  "vivariumsettingsfile");
if (v !== undefined) return { payload: v };
return null;

// Toggle output each time a message arrives
let uvLights = context.get('uvLights') || false;  // get previous state, default false

uvLights = !uvLights;              // flip the state
context.set('uvLights', uvLights); // remember it

return { payload:{lighting: uvLights?"on":"off"} };   // send true/false (on/off)

// UVC detection
let treshold = 1.5;     // Noise treshold

if(msg.topic === "uvc"){
    if(msg.payload >= treshold){
        msg.payload = "UVC alarm!"
    }
    else {
        msg.payload = "OK"
    }
    return msg
}
